import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Caricare i Log","description":"Come caricare i log per la risoluzione dei problemi.","frontmatter":{"title":"Caricare i Log","description":"Come caricare i log per la risoluzione dei problemi.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"it_it/1.21.4/players/troubleshooting/uploading-logs.md","filePath":"versions/1.21.4/translated/it_it/players/troubleshooting/uploading-logs.md","lastUpdated":1760721669000}`);var a={name:`it_it/1.21.4/players/troubleshooting/uploading-logs.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Caricare i Log <a class="header-anchor" href="#h1" aria-label="Permalink to “Caricare i Log”">​</a></h1><p>Quando stai tentando di risolvere problemi, spesso è necessario fornire i log per aiutare a identificare la causa del problema.</p><h2 id="why-should-i-upload-logs" tabindex="-1">Perché Dovrei Caricare i Log? <a class="header-anchor" href="#why-should-i-upload-logs" aria-label="Permalink to “Perché Dovrei Caricare i Log?”">​</a></h2><p>Caricare i log permette agli altri di aiutarti a risolvere i tuoi problemi molto più velocemente che non semplicemente incollare i log in una chat o in un post su un forum. Ti permette anche di condividere i tuoi log con altri senza doverli copiare e incollare.</p><p>Alcuni siti forniscono anche colorazione della sintassi per i log, che li rende più facili da leggere, e potrebbero censurare informazioni riservate, come il tuo nome utente, o informazioni sul sistema.</p><h2 id="crash-reports" tabindex="-1">Segnalazioni dei Crash <a class="header-anchor" href="#crash-reports" aria-label="Permalink to “Segnalazioni dei Crash”">​</a></h2><p>Le segnalazioni dei crash sono generate automaticamente quando il gioco subisce un crash. Contengono soltanto informazioni sul crash e non i log reali del gioco. Esse sono posizionate nella cartella <code>crash-reports</code> nella directory del gioco.</p><p>Per maggiori informazioni sulle segnalazioni dei crash, vedi <a href="./crash-reports">Segnalazioni dei Crash</a>.</p><h2 id="locating-logs" tabindex="-1">Localizzare i Log <a class="header-anchor" href="#locating-logs" aria-label="Permalink to “Localizzare i Log”">​</a></h2><p>Questa guida ricopre il Launcher di Minecraft ufficiale (anche comunemente noto come il &quot;launcher vanilla&quot;) - per launcher di terze parti, dovresti consultare la loro documentazione.</p><p>I log sono posizionati nella cartella <code>logs</code> della directory del gioco, la directory del gioco può essere trovata nelle seguenti posizioni a seconda del tuo sistema operativo:</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-33" id="tab-34" checked><label data-title="Windows" for="tab-34">Windows</label><input type="radio" name="group-33" id="tab-35"><label data-title="macOS" for="tab-35">macOS</label><input type="radio" name="group-33" id="tab-36"><label data-title="Linux" for="tab-36">Linux</label></div><div class="blocks"><div class="language- active"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft</span></span></code></pre></div></div></div><p>Il log più recente si chiama <code>latest.log</code>, e log precedenti usano lo schema di denominazione <code>aaaa-mm-gg_numero.log.gz</code>.</p><h2 id="uploading-logs-online" tabindex="-1">Caricare i Log Online <a class="header-anchor" href="#uploading-logs-online" aria-label="Permalink to “Caricare i Log Online”">​</a></h2><p>I log possono essere caricati su vari servizi, come:</p><ul><li><a href="https://pastebin.com/" target="_blank" rel="noreferrer">Pastebin</a></li><li><a href="https://gist.github.com/" target="_blank" rel="noreferrer">Gist di GitHub</a></li><li><a href="https://mclo.gs/" target="_blank" rel="noreferrer">mclo.gs</a></li></ul>`,16)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};